INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000001, "カリン", "2025/01/31 12:00:00", 1, 2, 1, 1, 3.414, "2030/01/01 14:59:59", -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 190805, 62, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000002, "カリン", "2025/01/31 12:00:00", 1, 2, 1, 2, 3.099, "2030/01/01 14:59:59", -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！", 190805, 62, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000003, "カリン", "2025/01/31 12:00:00", 1, 2, 1, 3, 2.801, "2030/01/01 14:59:59", -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", 190805, 63, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000004, "カリン", "2025/01/31 12:00:00", 1, 2, 2, 4, 0.0, "2030/01/01 14:59:59", -416.5, "報酬がもらえますよ！\nチェックしてみてください", 190805, 63, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000005, "カリン", "2025/01/31 12:00:00", 1, 1, 2, 5, 2.12, "2030/01/01 14:59:59", -363.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 190805, 64, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000006, "カリン", "2025/01/31 12:00:00", 1, 2, 1, 6, 1.68, "2030/01/01 14:59:59", -363.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 190805, 64, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1000007, "カリン", "2025/01/31 12:00:00", 1, 1, 2, 7, 2.33, "2030/01/01 14:59:59", -363.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 190805, 64, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020101, "ラビリスタ", "2025/01/31 12:00:00", 10201, 7, 3, 101, 5.18, "2030/01/01 14:59:59", -285.0, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 133701, 61, -6.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020102, "クリスティーナ", "2025/01/31 12:00:00", 10201, 2, 1, 201, 8.77, "2030/01/01 14:59:59", -285.0, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 133901, 61, -2.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020103, "ネネカ", "2025/01/31 12:00:00", 10201, 1, 6, 301, 15.5, "2030/01/01 14:59:59", -285.0, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 133801, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020201, "ランファ", "2025/02/28 12:00:00", 10202, 5, 2, 101, 9.061, "2030/01/01 14:59:59", -285.0, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 134301, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020202, "チカ", "2025/02/28 12:00:00", 10202, 2, 1, 201, 7.699, "2030/01/01 14:59:59", -285.0, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 134401, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020301, "アオイ", "2025/03/31 12:00:00", 10203, 2, 1, 101, 8.595, "2030/01/01 14:59:59", -285.0, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 134601, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020302, "クローチェ", "2025/03/31 12:00:00", 10203, 2, 1, 201, 7.758, "2030/01/01 14:59:59", -285.0, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 134501, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020401, "ルイズマリー", "2025/04/30 12:00:00", 10204, 6, 2, 101, 7.0, "2030/01/01 14:59:59", -285.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 132302, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020402, "イロハ", "2025/04/30 12:00:00", 10204, 2, 1, 201, 7.904, "2030/01/01 14:59:59", -285.0, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 132402, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020403, "ソノ", "2025/04/30 12:00:00", 10204, 2, 4, 301, 8.487, "2030/01/01 14:59:59", -285.0, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 132502, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020502, "カノン", "2025/05/31 12:00:00", 10205, 2, 1, 101, 8.763, "2030/01/01 14:59:59", -285.0, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 134901, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020503, "ツムギ", "2025/05/31 12:00:00", 10205, 3, 1, 201, 6.417, "2030/01/01 14:59:59", -285.0, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 134801, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020601, "エリス", "2025/06/30 12:00:00", 10206, 7, 3, 101, 10.335, "2030/01/01 14:59:59", -285.0, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 135001, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020602, "シェフィ", "2025/06/30 12:00:00", 10206, 4, 2, 201, 6.281, "2030/01/01 14:59:59", -285.0, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 135101, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020603, "プレシア", "2025/06/30 12:00:00", 10206, 2, 1, 301, 12.244, "2030/01/01 14:59:59", -285.0, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 135201, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020701, "クリア", "2025/07/31 12:00:00", 10207, 8, 2, 101, 6.339, "2030/01/01 14:59:59", -285.0, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 135301, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020702, "アネモネ", "2025/07/31 12:00:00", 10207, 9, 7, 201, 8.184, "2030/01/01 14:59:59", -285.0, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 135401, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020801, "アイラ", "2025/08/31 12:00:00", 10208, 2, 9, 101, 3.906, "2030/01/01 14:59:59", -285.0, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 129101, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020802, "シナツ", "2025/08/31 12:00:00", 10208, 2, 1, 201, 14.465, "2030/01/01 14:59:59", -285.0, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 129201, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020803, "ヒヨリ", "2025/08/31 12:00:00", 10208, 3, 4, 301, 8.662, "2030/01/01 14:59:59", -285.0, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 100101, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020804, "レイ", "2025/08/31 12:00:00", 10208, 3, 1, 401, 10.915, "2030/01/01 14:59:59", -285.0, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 100301, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020901, "ユキノ", "2025/09/30 12:00:00", 10209, 7, 1, 101, 6.042, "2030/01/01 14:59:59", -285.0, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 135802, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020902, "サツキ", "2025/09/30 12:00:00", 10209, 1, 4, 201, 9.402, "2030/01/01 14:59:59", -285.0, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 135903, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1020903, "ルルィ", "2025/09/30 12:00:00", 10209, 1, 8, 301, 8.16, "2030/01/01 14:59:59", -285.0, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 136902, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021001, "カスミ", "2025/10/31 12:00:00", 10210, 2, 3, 101, 5.0, "2030/01/01 14:59:59", -285.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 137401, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021002, "アラクネ", "2025/10/31 12:00:00", 10210, 1, 4, 201, 8.12, "2030/01/01 14:59:59", -285.0, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 136001, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021003, "ナーナ", "2025/10/31 12:00:00", 10210, 2, 4, 301, 6.386, "2030/01/01 14:59:59", -285.0, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 136202, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021101, "ユイ", "2025/11/30 12:00:00", 10211, 4, 3, 101, 7.438, "2030/01/01 14:59:59", -285.0, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 136402, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021102, "ミソラ", "2025/11/30 12:00:00", 10211, 5, 1, 201, 8.35, "2030/01/01 14:59:59", -285.0, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 136302, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021201, "シズル", "2025/12/31 12:00:00", 10212, 2, 1, 101, 5.0, "2030/01/01 14:59:59", -285.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 136501, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021202, "リノ", "2025/12/31 12:00:00", 10212, 2, 1, 201, 5.25, "2030/01/01 14:59:59", -285.0, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 137902, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021203, "ラビリスタ", "2025/12/31 12:00:00", 10212, 2, 1, 301, 7.5, "2030/01/01 14:59:59", -285.0, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 106801, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021301, "ライラエル", "2026/01/31 12:00:00", 10213, 2, 1, 101, 8.204, "2030/01/01 14:59:59", -285.0, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 126501, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021302, "ネフィ＝ネラ", "2026/01/31 12:00:00", 10213, 2, 1, 201, 7.176, "2030/01/01 14:59:59", -285.0, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 129701, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021303, "ヴァイオレット", "2026/01/31 12:00:00", 10213, 5, 1, 301, 8.602, "2030/01/01 14:59:59", -285.0, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 133101, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021304, "ライラエル", "2026/02/06 12:00:00", 10213, 3, 1, 102, 10.14, "2030/01/01 14:59:59", -285.0, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 138101, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021305, "ネフィ＝ネラ", "2026/02/06 12:00:00", 10213, 7, 1, 202, 10.152, "2030/01/01 14:59:59", -285.0, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 138201, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021306, "ヴァイオレット", "2026/02/06 12:00:00", 10213, 3, 4, 302, 9.688, "2030/01/01 14:59:59", -285.0, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 138001, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021307, "ペコリーヌ", "2026/02/12 12:00:00", 10213, 1, 2, 401, 5.928, "2030/01/01 14:59:59", -285.0, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 138301, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021401, "ワカナ", "2026/02/28 12:00:00", 10214, 2, 4, 101, 9.19, "2030/01/01 14:59:59", -285.0, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 138702, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021402, "シオリ", "2026/02/28 12:00:00", 10214, 3, 1, 201, 8.724, "2030/01/01 14:59:59", -285.0, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 138802, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021501, "グレイス", "2026/03/31 12:00:00", 10215, 1, 4, 101, 7.758, "2030/01/01 14:59:59", -285.0, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 138902, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021502, "キョウカ", "2026/03/31 12:00:00", 10215, 4, 6, 201, 6.375, "2030/01/01 14:59:59", -285.0, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 139002, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021503, "ルルィ", "2026/03/31 12:00:00", 10215, 1, 6, 301, 6.173, "2030/01/01 14:59:59", -285.0, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 136902, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021601, "ミホ", "2026/04/30 12:00:00", 10216, 2, 6, 101, 4.202, "2030/01/01 14:59:59", -285.0, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 139202, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021602, "マホ", "2026/04/30 12:00:00", 10216, 1, 6, 201, 2.842, "2030/01/01 14:59:59", -285.0, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 139302, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021603, "エリカ", "2026/04/30 12:00:00", 10216, 1, 4, 301, 4.598, "2030/01/01 14:59:59", -285.0, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 139402, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021701, "リリ", "2026/05/31 12:00:00", 10217, 3, 4, 101, 6.533, "2030/01/01 14:59:59", -285.0, "わたくしたちの悲願は、ロストさせ\nてしまった方々をお助けすること…\nそのためなら、どのような辛苦にも\n耐え抜いてみせます…！", 125802, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021702, "プレシア", "2026/05/31 12:00:00", 10217, 3, 3, 301, 5.0, "2030/01/01 14:59:59", -285.0, "みんなも。せーぎも。\nクリアも。パパ、も。\nぜったい、たすける。\nみててね。お兄。", 126102, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021703, "クリア", "2026/05/31 12:00:00", 10217, 4, 3, 201, 5.214, "2030/01/01 14:59:59", -285.0, "癒しの力を使うこと…\nもう、ためらいません！\nモネちゃんやお兄さん…\nみんなに許してもらうためにも！", 126002, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021704, "リリ", "2026/05/31 12:00:00", 10217, 3, 1, 102, 8.781, "2030/01/01 14:59:59", -285.0, "ヴァルキュリア─皆様を助けたい\nという願いを、力にできるのなら…\nわたくしたちは、きっと誰にも\n負けません！　一意専心です…！", 139501, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021705, "クリア", "2026/05/31 12:00:00", 10217, 1, 2, 202, 6.529, "2030/01/01 14:59:59", -285.0, "このヴァルキュリアって職業、\nまるで天使みたいな格好ですよね\nうーん…『聖女』ちゃんって\n呼ばれるよりは、マシかな？", 139601, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021706, "プレシア", "2026/05/31 12:00:00", 10217, 2, 3, 302, 3.195, "2030/01/01 14:59:59", -285.0, "ばるきり。もーど。\nはね。まっしろ。\nはっぴーちゃんと。おなじ。\nいいかんじ。", 139701, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021801, "ルイズマリー", "2026/06/30 12:00:00", 10218, 3, 2, 101, 12.43, "2030/01/01 14:59:59", -285.0, "ダーリンと一緒に南の島で\nリゾート開発なんて夢みたい♪\nああ…幸せ、最高の夏だわ…\n触れたら爆発さえしなければ～…っ", 139902, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (1021802, "クレジッタ", "2026/06/30 12:00:00", 10218, 3, 2, 201, 6.35, "2030/01/01 14:59:59", -285.0, "青い空、白い雲…無人島リゾートで\n大儲けですわ～♪　こらこらそこ、\nイチャついてるんじゃないですのよ\n触れたらドカンですわよ、ドカン！", 140001, 61, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000001, "カリン", "2026/04/10 12:00:00", 2, 2, 1, 1, 3.414, "2030/01/01 14:59:59", -416.5, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 190801, 62, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000002, "カリン", "2026/04/10 12:00:00", 2, 2, 1, 2, 3.099, "2030/01/01 14:59:59", -416.5, "ミッションをクリアして、\n報酬をゲットしましょう！", 190801, 62, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000003, "カリン", "2026/04/10 12:00:00", 2, 2, 1, 3, 2.801, "2030/01/01 14:59:59", -416.5, "受け取ることができる\n報酬があるようです\n確認してみてください", 190801, 63, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000004, "カリン", "2026/04/10 12:00:00", 2, 2, 2, 4, 0.0, "2030/01/01 14:59:59", -416.5, "報酬がもらえますよ！\nチェックしてみてください", 190801, 63, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000005, "カリン", "2026/04/10 12:00:00", 2, 1, 2, 5, 2.12, "2030/01/01 14:59:59", -363.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 190801, 64, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000006, "カリン", "2026/04/10 12:00:00", 2, 2, 1, 6, 1.68, "2030/01/01 14:59:59", -363.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 190801, 64, 0.0);
INSERT INTO `v1_13a6eec6686b8c5e7e40248b8203293cf074460dc87d49d7e0b1c01af0493013` VALUES (2000007, "カリン", "2026/04/10 12:00:00", 2, 1, 2, 7, 2.33, "2030/01/01 14:59:59", -363.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 190801, 64, 0.0);
